import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getEventsByOrganiser, getReservationsByOrganiser, getTransactionsByOrganiser } from '../../api/api';
import { useAuth } from '../../context/AuthContext';

const AdminDashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState({ events: 0, bookings: 0, revenue: 0, cancellations: 0 });
  const [recentBookings, setRecentBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tick, setTick] = useState(0);

  // Live clock tick
  useEffect(() => {
    const id = setInterval(() => setTick((t) => t + 1), 1000);
    return () => clearInterval(id);
  }, []);

  const now = new Date();
  const timeStr = now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
  const dateStr = now.toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

  useEffect(() => {
    const load = async () => {
      try {
        const [evRes, bkRes, txRes] = await Promise.all([
          getEventsByOrganiser(user.userId),
          getReservationsByOrganiser(user.userId),
          getTransactionsByOrganiser(user.userId),
        ]);
        const events   = evRes.data?.data  || [];
        const bookings = bkRes.data?.data  || [];
        const txns     = txRes.data?.data  || [];
        const revenue  = txns
          .filter((t) => t.status === 'SUCCESS' || t.status === 'REFUNDED' || t.status === 'CREDITED')
          .reduce((s, t) => s + parseFloat(t.amount || 0), 0);
        const cancellations = bookings.filter((b) => b.status === 'CANCELLED').length;
        setStats({ events: events.length, bookings: bookings.length, revenue, cancellations });
        setRecentBookings([...bookings].reverse().slice(0, 6));
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
    };
    load();
  }, [user.userId]);

  const confirmedPct = stats.bookings > 0
    ? Math.round(((stats.bookings - stats.cancellations) / stats.bookings) * 100)
    : 0;

  const QUICK = [
    { label: 'Create Event',  icon: '＋', desc: 'Add new event',        path: '/admin/events',   accent: '#e05c2a' },
    { label: 'Add Slot',      icon: '◷',  desc: 'Schedule show times',  path: '/admin/slots',    accent: '#2563a8' },
    { label: 'Manage Seats',  icon: '⊞',  desc: 'Configure seat layout', path: '/admin/seats',   accent: '#1a8f63' },
    { label: 'Payments',      icon: '₹',  desc: 'Full payment history',  path: '/admin/payments', accent: '#c97d1a' },
  ];

  return (
    <div style={{
      background: '#0f1117',
      minHeight: '100vh',
      fontFamily: '"DM Sans", system-ui, sans-serif',
      color: '#e8e4de',
    }}>

      {/* ── Top bar ── */}
      <div style={{
        borderBottom: '1px solid rgba(255,255,255,0.07)',
        padding: '16px 40px',
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        background: 'rgba(255,255,255,0.02)',
        backdropFilter: 'blur(20px)',
        position: 'sticky', top: 0, zIndex: 10,
      }}>
        <div>
          <div style={{ fontSize: '11px', letterSpacing: '0.15em', color: '#6b7280', textTransform: 'uppercase', fontWeight: 600 }}>
            Organiser Panel
          </div>
          <div style={{ fontSize: '20px', fontWeight: 700, color: '#f3f0eb', marginTop: '2px' }}>
            Welcome back, <span style={{ color: '#e05c2a' }}>{user.name}</span>
          </div>
        </div>

        {/* Live clock */}
        <div style={{ textAlign: 'right' }}>
          <div style={{
            fontFamily: '"JetBrains Mono", monospace',
            fontSize: '28px', fontWeight: 700,
            color: '#e05c2a', letterSpacing: '0.05em',
            lineHeight: 1,
          }}>
            {timeStr}
          </div>
          <div style={{ fontSize: '11px', color: '#6b7280', marginTop: '4px', letterSpacing: '0.05em' }}>
            {dateStr}
          </div>
        </div>
      </div>

      <div style={{ padding: '32px 40px', maxWidth: '1400px', margin: '0 auto' }}>

        {/* ── Stat cards ── */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '16px', marginBottom: '32px' }}>
          {[
            { label: 'EVENTS',       value: stats.events,                     sub: 'Active shows',          accent: '#e05c2a', icon: '🎭', path: '/admin/events' },
            { label: 'BOOKINGS',     value: stats.bookings,                   sub: `${confirmedPct}% confirmed`, accent: '#1a8f63', icon: '🎟', path: '/admin/bookings' },
            { label: 'REVENUE',      value: `₹${stats.revenue.toLocaleString('en-IN', { maximumFractionDigits: 0 })}`, sub: 'Total collected', accent: '#c97d1a', icon: '💰', path: '/admin/payments' },
            { label: 'CANCELLATIONS', value: stats.cancellations,             sub: 'Need attention',         accent: '#e8305a', icon: '⚠', path: '/admin/bookings' },
          ].map((s, i) => (
            <div key={s.label} onClick={() => navigate(s.path)}
              style={{
                background: 'rgba(255,255,255,0.03)',
                border: '1px solid rgba(255,255,255,0.08)',
                borderRadius: '16px',
                padding: '24px',
                cursor: 'pointer',
                position: 'relative',
                overflow: 'hidden',
                transition: 'all 0.2s',
                animationDelay: `${i * 0.08}s`,
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = 'rgba(255,255,255,0.06)';
                e.currentTarget.style.borderColor = s.accent + '60';
                e.currentTarget.style.transform = 'translateY(-2px)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = 'rgba(255,255,255,0.03)';
                e.currentTarget.style.borderColor = 'rgba(255,255,255,0.08)';
                e.currentTarget.style.transform = 'none';
              }}
            >
              {/* Glow blob */}
              <div style={{
                position: 'absolute', top: 0, right: 0,
                width: '120px', height: '120px',
                background: `radial-gradient(circle, ${s.accent}20 0%, transparent 70%)`,
                borderRadius: '50%',
                transform: 'translate(30%, -30%)',
                pointerEvents: 'none',
              }} />

              <div style={{ fontSize: '11px', letterSpacing: '0.15em', color: '#6b7280', fontWeight: 700, marginBottom: '16px' }}>
                {s.label}
              </div>
              <div style={{
                fontFamily: '"JetBrains Mono", monospace',
                fontSize: '36px', fontWeight: 700,
                color: s.accent, lineHeight: 1,
                marginBottom: '8px',
              }}>
                {loading ? '—' : s.value}
              </div>
              <div style={{ fontSize: '12px', color: '#6b7280' }}>{s.sub}</div>

              {/* Bottom accent bar */}
              <div style={{
                position: 'absolute', bottom: 0, left: 0, right: 0,
                height: '2px',
                background: `linear-gradient(90deg, ${s.accent}, transparent)`,
              }} />
            </div>
          ))}
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: '24px' }}>

          {/* ── Recent Bookings ── */}
          <div style={{
            background: 'rgba(255,255,255,0.03)',
            border: '1px solid rgba(255,255,255,0.08)',
            borderRadius: '16px', overflow: 'hidden',
          }}>
            <div style={{
              padding: '20px 24px',
              borderBottom: '1px solid rgba(255,255,255,0.07)',
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            }}>
              <div>
                <div style={{ fontSize: '13px', fontWeight: 700, color: '#f3f0eb' }}>Recent Bookings</div>
                <div style={{ fontSize: '11px', color: '#6b7280', marginTop: '2px' }}>Last {recentBookings.length} transactions</div>
              </div>
              <div style={{
                width: '8px', height: '8px', borderRadius: '50%',
                background: '#1a8f63',
                boxShadow: '0 0 8px #1a8f63',
                animation: 'pulse 2s infinite',
              }} />
            </div>

            {loading ? (
              <div style={{ padding: '60px', textAlign: 'center', color: '#6b7280' }}>Loading...</div>
            ) : recentBookings.length === 0 ? (
              <div style={{ padding: '60px', textAlign: 'center', color: '#6b7280' }}>No bookings yet</div>
            ) : (
              <div>
                {/* Header row */}
                <div style={{
                  display: 'grid', gridTemplateColumns: '1fr 140px 100px 90px',
                  padding: '10px 24px',
                  fontSize: '10px', fontWeight: 700, letterSpacing: '0.1em',
                  color: '#4b5563', textTransform: 'uppercase',
                  borderBottom: '1px solid rgba(255,255,255,0.04)',
                }}>
                  <span>Event / Ref</span>
                  <span>Date</span>
                  <span style={{ textAlign: 'right' }}>Amount</span>
                  <span style={{ textAlign: 'right' }}>Status</span>
                </div>
                {recentBookings.map((r, i) => {
                  const isConfirmed = r.status === 'CONFIRMED';
                  const isCancelled = r.status === 'CANCELLED';
                  return (
                    <div key={r.reservationId} style={{
                      display: 'grid', gridTemplateColumns: '1fr 140px 100px 90px',
                      padding: '14px 24px', alignItems: 'center',
                      borderBottom: i < recentBookings.length - 1 ? '1px solid rgba(255,255,255,0.04)' : 'none',
                      transition: 'background 0.15s',
                    }}
                      onMouseEnter={(e) => e.currentTarget.style.background = 'rgba(255,255,255,0.03)'}
                      onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                    >
                      <div>
                        <div style={{ fontSize: '13px', fontWeight: 600, color: '#e8e4de', marginBottom: '2px' }}>
                          {r.slot?.event?.name || 'Event'}
                        </div>
                        <div style={{ fontFamily: '"JetBrains Mono", monospace', fontSize: '10px', color: '#4b5563' }}>
                          {r.refCode}
                        </div>
                      </div>
                      <div style={{ fontSize: '12px', color: '#6b7280' }}>
                        {r.reservedDate ? new Date(r.reservedDate).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }) : '—'}
                      </div>
                      <div style={{ textAlign: 'right', fontFamily: '"JetBrains Mono", monospace', fontSize: '14px', fontWeight: 700, color: '#e05c2a' }}>
                        ₹{parseFloat(r.amount || 0).toFixed(0)}
                      </div>
                      <div style={{ textAlign: 'right' }}>
                        <span style={{
                          fontSize: '10px', fontWeight: 700, padding: '3px 8px', borderRadius: '20px',
                          background: isConfirmed ? 'rgba(26,143,99,0.15)' : isCancelled ? 'rgba(232,48,90,0.15)' : 'rgba(201,125,26,0.15)',
                          color: isConfirmed ? '#1a8f63' : isCancelled ? '#e8305a' : '#c97d1a',
                          border: `1px solid ${isConfirmed ? 'rgba(26,143,99,0.3)' : isCancelled ? 'rgba(232,48,90,0.3)' : 'rgba(201,125,26,0.3)'}`,
                        }}>
                          {r.status}
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          {/* ── Right column ── */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>

            {/* Booking health */}
            <div style={{
              background: 'rgba(255,255,255,0.03)',
              border: '1px solid rgba(255,255,255,0.08)',
              borderRadius: '16px', padding: '24px',
            }}>
              <div style={{ fontSize: '11px', letterSpacing: '0.12em', color: '#6b7280', fontWeight: 700, marginBottom: '16px' }}>
                BOOKING HEALTH
              </div>
              <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px', marginBottom: '12px' }}>
                <span style={{ fontFamily: '"JetBrains Mono", monospace', fontSize: '48px', fontWeight: 700, color: '#1a8f63', lineHeight: 1 }}>
                  {confirmedPct}
                </span>
                <span style={{ fontSize: '20px', color: '#4b5563', fontWeight: 700 }}>%</span>
              </div>
              <div style={{ fontSize: '12px', color: '#6b7280', marginBottom: '16px' }}>confirmed bookings</div>
              {/* Progress bar */}
              <div style={{ height: '6px', background: 'rgba(255,255,255,0.08)', borderRadius: '99px', overflow: 'hidden' }}>
                <div style={{
                  height: '100%', width: `${confirmedPct}%`,
                  background: 'linear-gradient(90deg, #1a8f63, #00d68f)',
                  borderRadius: '99px',
                  transition: 'width 1s ease',
                }} />
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '8px', fontSize: '11px', color: '#4b5563' }}>
                <span>0%</span>
                <span>100%</span>
              </div>
            </div>

            {/* Quick actions */}
            <div style={{
              background: 'rgba(255,255,255,0.03)',
              border: '1px solid rgba(255,255,255,0.08)',
              borderRadius: '16px', padding: '24px',
            }}>
              <div style={{ fontSize: '11px', letterSpacing: '0.12em', color: '#6b7280', fontWeight: 700, marginBottom: '16px' }}>
                QUICK ACTIONS
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                {QUICK.map((q) => (
                  <div key={q.label} onClick={() => navigate(q.path)}
                    style={{
                      display: 'flex', alignItems: 'center', gap: '14px',
                      padding: '12px 14px', borderRadius: '10px',
                      border: '1px solid rgba(255,255,255,0.06)',
                      cursor: 'pointer', transition: 'all 0.15s',
                      background: 'transparent',
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.background = `${q.accent}12`;
                      e.currentTarget.style.borderColor = `${q.accent}40`;
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.background = 'transparent';
                      e.currentTarget.style.borderColor = 'rgba(255,255,255,0.06)';
                    }}
                  >
                    <div style={{
                      width: 36, height: 36, borderRadius: '8px',
                      background: `${q.accent}20`,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: '16px', color: q.accent, fontWeight: 700, flexShrink: 0,
                    }}>
                      {q.icon}
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: '13px', fontWeight: 600, color: '#e8e4de' }}>{q.label}</div>
                      <div style={{ fontSize: '11px', color: '#4b5563' }}>{q.desc}</div>
                    </div>
                    <span style={{ color: '#4b5563', fontSize: '14px' }}>→</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.4; }
        }
      `}</style>
    </div>
  );
};

export default AdminDashboard;
